TriggerOraclev10g.body:
DECLARE
  PRAGMA AUTONOMOUS_TRANSACTION;
  v_action VARCHAR2(50);
BEGIN
  IF INSERTING THEN
    v_action := 'INSERT';
  ELSE
    v_action := 'UPDATE';
  END IF;

  pkg_audit.log_fga('NGUYENLIEU', 'fga_nguyenlieu_sensitive',
    v_action || ' nguyĂªn liá»‡u sensitive: ' || :NEW.TENNL || ' (Level: ' || :NEW.SECURITY_LEVEL || ')');
EXCEPTION
  WHEN OTHERS THEN NULL;
END;
